import React, { useState, useEffect } from 'react';
import { useNavigate } from 'react-router-dom';
import { 
  Container, 
  Paper, 
  Typography, 
  Box, 
  Table, 
  TableBody, 
  TableCell, 
  TableContainer, 
  TableHead, 
  TableRow,
  TablePagination,
  Chip,
  TextField,
  InputAdornment,
  CircularProgress,
  Alert,
  Toolbar,
  IconButton,
  Menu,
  MenuItem,
  FormControl,
  InputLabel,
  Select,
  Grid,
  Dialog,
  DialogTitle,
  DialogContent,
  DialogActions,
  Button,
  Divider,
} from '@mui/material';
import {
  Search,
  FilterList,
  ArrowUpward,
  ArrowDownward,
  SwapHoriz,
  ContentCopy,
  Info,
  Download,
  ReceiptLong
} from '@mui/icons-material';
import { useAuth } from '../context/AuthContext';
import api from '../utils/api';
import { format } from 'date-fns';

const Transactions = () => {
  const navigate = useNavigate();
  const { currentUser } = useAuth();
  const [transactions, setTransactions] = useState([]);
  const [loading, setLoading] = useState(true);
  const [error, setError] = useState(null);
  const [page, setPage] = useState(0);
  const [rowsPerPage, setRowsPerPage] = useState(10);
  const [totalCount, setTotalCount] = useState(0);
  const [searchTerm, setSearchTerm] = useState('');
  const [anchorEl, setAnchorEl] = useState(null);
  const [filters, setFilters] = useState({
    type: 'all',
    dateRange: 'all',
    status: 'all',
    wallet: 'all'
  });
  const [wallets, setWallets] = useState([]);
  const [selectedTransaction, setSelectedTransaction] = useState(null);
  const [detailsOpen, setDetailsOpen] = useState(false);
  const [copySuccess, setCopySuccess] = useState('');
  const [statusFilter, setStatusFilter] = useState('all');
  const [typeFilter, setTypeFilter] = useState('all');
  const [sortField, setSortField] = useState('date');
  const [sortDirection, setSortDirection] = useState('desc');
  const [walletFilter, setWalletFilter] = useState('all');

  // Safe formatting functions to avoid undefined errors
  const formatCurrency = (amount, currency = 'USD') => {
    const numAmount = Number(amount || 0);
    return new Intl.NumberFormat('en-US', {
      style: 'currency',
      currency: currency || 'USD'
    }).format(numAmount);
  };

  const formatDateSafely = (dateString) => {
    if (!dateString) return 'N/A';

    try {
      return format(new Date(dateString), 'MMM d, yyyy HH:mm');
    } catch (error) {
      console.error('Error formatting date:', error);
      return 'Invalid date';
    }
  };

  const determineTransactionType = (transaction) => {
    if (!transaction) return 'UNKNOWN';

    if (transaction.type) return transaction.type.toString().toUpperCase();
    if (transaction.transaction_type) return transaction.transaction_type.toString().toUpperCase();

    // If we have the current user, determine if it's a send or receive
    if (currentUser && currentUser.id) {
      if (transaction.sender_id === currentUser.id) return 'SEND';
      if (transaction.recipient_id === currentUser.id) return 'RECEIVE';
    }

    return 'TRANSFER';
  };

  // Safely process transactions to prevent null/undefined errors
  const processTransactions = (data) => {
    if (!Array.isArray(data)) {
      console.warn('Transaction data is not an array:', data);
      return [];
    }

    return data.map(transaction => {
      if (!transaction) return null;

      // Safely extract values with fallbacks
      const amount = transaction.amount || transaction.source_amount || 0;
      const currency = transaction.currency || transaction.source_currency || 'USD';
      const date = transaction.date || transaction.timestamp || null;
      const status = (transaction.status || 'Completed').toString();

      return {
        ...transaction,
        formattedAmount: formatCurrency(amount, currency),
        formattedDate: formatDateSafely(date),
        type: determineTransactionType(transaction),
        status: status
      };
    }).filter(Boolean); // Remove any null entries
  };

  useEffect(() => {
    fetchTransactions();
    fetchWallets();
  }, [page, rowsPerPage, filters]);

  const fetchTransactions = async () => {
    setLoading(true);
    setError(null);

    try {
      console.log('Fetching transactions...');
      let transactionsData = [];

      // Try to get transactions for the specific user if we have a user ID
      if (currentUser && currentUser.id) {
        try {
          const response = await api.get(`/transaction/user/${currentUser.id}`);
          console.log('User transactions response:', response.data);
          if (Array.isArray(response.data)) {
            transactionsData = response.data;
          } else if (response.data && Array.isArray(response.data.transactions)) {
            transactionsData = response.data.transactions;
          }
        } catch (userTransactionsErr) {
          console.warn('Error fetching user-specific transactions, trying general endpoint:', userTransactionsErr);
        }
      }

      // If we couldn't get user-specific transactions or they were empty, try the general endpoint
      if (transactionsData.length === 0) {
        try {
          const allTransactionsResponse = await api.get('/transaction/');
          console.log('All transactions response:', allTransactionsResponse.data);
          if (Array.isArray(allTransactionsResponse.data)) {
            transactionsData = allTransactionsResponse.data;
          } else if (allTransactionsResponse.data && Array.isArray(allTransactionsResponse.data.transactions)) {
            transactionsData = allTransactionsResponse.data.transactions;
          }
        } catch (allTransactionsErr) {
          console.error('Error fetching all transactions:', allTransactionsErr);
          throw allTransactionsErr; // Re-throw to be caught by the outer catch
        }
      }

      // Process transaction data with our safe function
      const processedTransactions = processTransactions(transactionsData);

      console.log('Processed transactions:', processedTransactions);
      setTransactions(processedTransactions);
    } catch (err) {
      console.error('Error fetching transactions:', err);
      setError('Failed to load transactions. Please try again.');
    } finally {
      setLoading(false);
    }
  };

  const fetchWallets = async () => {
    try {
      // Try to get wallets for the specific user if we have a user ID
      if (currentUser && currentUser.id) {
        try {
          const response = await api.get(`/wallet/${currentUser.id}`);
          if (Array.isArray(response.data)) {
            setWallets(response.data);
          } else if (response.data) {
            setWallets([response.data]);
          }
        } catch (error) {
          console.warn('Error fetching user wallets:', error);
          // Try the general endpoint
          const allWalletsResponse = await api.get('/wallet/');
          if (Array.isArray(allWalletsResponse.data)) {
            setWallets(allWalletsResponse.data);
          } else if (allWalletsResponse.data) {
            setWallets([allWalletsResponse.data]);
          }
        }
      }
    } catch (err) {
      console.error('Error fetching wallets for filter:', err);
    }
  };

  const handleChangePage = (event, newPage) => {
    setPage(newPage);
  };

  const handleChangeRowsPerPage = (event) => {
    setRowsPerPage(parseInt(event.target.value, 10));
    setPage(0);
  };

  const handleSearchChange = (e) => {
    setSearchTerm(e.target.value);
  };

  const handleSearch = (e) => {
    if (e.key === 'Enter') {
      fetchTransactions();
    }
  };

  const handleFilterMenuOpen = (event) => {
    setAnchorEl(event.currentTarget);
  };

  const handleFilterMenuClose = () => {
    setAnchorEl(null);
  };

  const handleFilterChange = (name, value) => {
    setFilters({
      ...filters,
      [name]: value
    });
    setPage(0); // Reset to first page when filter changes
  };

  const handleViewDetails = (transaction) => {
    setSelectedTransaction(transaction);
    setDetailsOpen(true);
  };

  const handleCloseDetails = () => {
    setDetailsOpen(false);
  };

  const copyToClipboard = (text, type) => {
    navigator.clipboard.writeText(text).then(
      () => {
        setCopySuccess(`${type} copied!`);
        setTimeout(() => setCopySuccess(''), 2000);
      },
      () => {
        setCopySuccess('Failed to copy');
      }
    );
  };

  const getStatusChip = (status) => {
    let color = 'default';

    switch (status.toUpperCase()) {
      case 'COMPLETED':
        color = 'success';
        break;
      case 'PENDING':
        color = 'warning';
        break;
      case 'FAILED':
        color = 'error';
        break;
      default:
        color = 'default';
    }

    return <Chip label={status} color={color} size="small" />;
  };

  const getTypeIcon = (type) => {
    if (type === 'DEPOSIT' || type === 'RECEIVE') return <ArrowDownward fontSize="small" color="success" />;
    if (type === 'WITHDRAWAL' || type === 'SEND') return <ArrowUpward fontSize="small" color="error" />;
    return <SwapHoriz fontSize="small" color="primary" />;
  };

  const formatDate = (dateString) => {
    const options = { year: 'numeric', month: 'short', day: 'numeric', hour: '2-digit', minute: '2-digit' };
    return new Date(dateString).toLocaleDateString('en-US', options);
  };

  const getWalletName = (walletId) => {
    const wallet = wallets.find(w => w.id === walletId);
    return wallet ? wallet.name : 'Unknown Wallet';
  };

  const handleStatusFilterChange = (event) => {
    setStatusFilter(event.target.value);
    setPage(0);
  };

  const handleTypeFilterChange = (event) => {
    setTypeFilter(event.target.value);
    setPage(0);
  };

  const handleWalletFilterChange = (event) => {
    setWalletFilter(event.target.value);
    setPage(0);
  };

  const handleSortChange = (field) => {
    const isAsc = sortField === field && sortDirection === 'asc';
    setSortDirection(isAsc ? 'desc' : 'asc');
    setSortField(field);
  };

  // Filter transactions based on search term and filters
  const filteredTransactions = transactions.filter((transaction) => {
    // Search term filter
    const searchLower = searchTerm.toLowerCase();
    const matchesSearch = 
      transaction.id?.toString().includes(searchLower) ||
      transaction.formattedAmount?.toLowerCase().includes(searchLower) ||
      transaction.description?.toLowerCase().includes(searchLower) ||
      transaction.formattedDate?.toLowerCase().includes(searchLower) ||
      transaction.type?.toLowerCase().includes(searchLower);

    // Status filter
    const matchesStatus = statusFilter === 'all' || 
      transaction.status?.toLowerCase() === statusFilter.toLowerCase();

    // Type filter
    const matchesType = typeFilter === 'all' || 
      transaction.type?.toLowerCase() === typeFilter.toLowerCase();

    // Wallet filter
    const matchesWallet = walletFilter === 'all' || 
      transaction.from_wallet_id?.toString() === walletFilter ||
      transaction.to_wallet_id?.toString() === walletFilter;

    return matchesSearch && matchesStatus && matchesType && matchesWallet;
  });

  // Sort filtered transactions
  const sortedTransactions = filteredTransactions.sort((a, b) => {
    let comparison = 0;

    switch (sortField) {
      case 'date':
        comparison = new Date(b.date || 0) - new Date(a.date || 0);
        break;
      case 'amount':
        comparison = (b.amount || 0) - (a.amount || 0);
        break;
      case 'description':
        comparison = (a.description || '').localeCompare(b.description || '');
        break;
      case 'status':
        comparison = (a.status || '').localeCompare(b.status || '');
        break;
      case 'type':
        comparison = (a.type || '').localeCompare(b.type || '');
        break;
      default:
        comparison = 0;
    }

    return sortDirection === 'asc' ? comparison : -comparison;
  });

  // Paginate
  const paginatedTransactions = sortedTransactions.slice(
    page * rowsPerPage,
    page * rowsPerPage + rowsPerPage
  );

  return (
    <Container maxWidth="lg">
      <Box sx={{ mt: 4, mb: 4 }}>
        <Paper sx={{ width: '100%', mb: 2 }}>
          <Toolbar sx={{ pl: { sm: 2 }, pr: { xs: 1, sm: 1 } }}>
            <Typography
              sx={{ flex: '1 1 100%' }}
              variant="h5"
              component="div"
            >
              Transactions
            </Typography>

            <Box sx={{ display: 'flex', alignItems: 'center' }}>
              <TextField
                margin="dense"
                placeholder="Search transactions..."
                variant="outlined"
                size="small"
                value={searchTerm}
                onChange={handleSearchChange}
                onKeyPress={handleSearch}
                InputProps={{
                  startAdornment: (
                    <InputAdornment position="start">
                      <Search />
                    </InputAdornment>
                  ),
                }}
                sx={{ mr: 2, width: '220px' }}
              />

              <IconButton onClick={handleFilterMenuOpen}>
                <FilterList />
              </IconButton>

              <Menu
                anchorEl={anchorEl}
                open={Boolean(anchorEl)}
                onClose={handleFilterMenuClose}
                sx={{ mt: 1 }}
              >
                <Box sx={{ px: 2, py: 1, width: 200 }}>
                  <FormControl fullWidth margin="dense" size="small">
                    <InputLabel id="transaction-type-label">Type</InputLabel>
                    <Select
                      labelId="transaction-type-label"
                      value={typeFilter}
                      label="Type"
                      onChange={handleTypeFilterChange}
                    >
                      <MenuItem value="all">All Types</MenuItem>
                      <MenuItem value="SEND">Send</MenuItem>
                      <MenuItem value="RECEIVE">Receive</MenuItem>
                      <MenuItem value="DEPOSIT">Deposit</MenuItem>
                      <MenuItem value="WITHDRAWAL">Withdrawal</MenuItem>
                      <MenuItem value="EXCHANGE">Exchange</MenuItem>
                    </Select>
                  </FormControl>

                  <FormControl fullWidth margin="dense" size="small">
                    <InputLabel id="transaction-date-label">Date Range</InputLabel>
                    <Select
                      labelId="transaction-date-label"
                      value={filters.dateRange}
                      label="Date Range"
                      onChange={(e) => handleFilterChange('dateRange', e.target.value)}
                    >
                      <MenuItem value="all">All Time</MenuItem>
                      <MenuItem value="7days">Last 7 Days</MenuItem>
                      <MenuItem value="30days">Last 30 Days</MenuItem>
                      <MenuItem value="90days">Last 90 Days</MenuItem>
                    </Select>
                  </FormControl>

                  <FormControl fullWidth margin="dense" size="small">
                    <InputLabel id="transaction-status-label">Status</InputLabel>
                    <Select
                      labelId="transaction-status-label"
                      value={statusFilter}
                      label="Status"
                      onChange={handleStatusFilterChange}
                    >
                      <MenuItem value="all">All Statuses</MenuItem>
                      <MenuItem value="COMPLETED">Completed</MenuItem>
                      <MenuItem value="PENDING">Pending</MenuItem>
                      <MenuItem value="FAILED">Failed</MenuItem>
                    </Select>
                  </FormControl>

                  <FormControl fullWidth margin="dense" size="small">
                    <InputLabel id="transaction-wallet-label">Wallet</InputLabel>
                    <Select
                      labelId="transaction-wallet-label"
                      value={walletFilter}
                      label="Wallet"
                      onChange={handleWalletFilterChange}
                    >
                      <MenuItem value="all">All Wallets</MenuItem>
                      {wallets.map((wallet) => (
                        <MenuItem key={wallet.id} value={wallet.id.toString()}>
                          {wallet.name}
                        </MenuItem>
                      ))}
                    </Select>
                  </FormControl>

                  <Box sx={{ mt: 2, display: 'flex', justifyContent: 'flex-end' }}>
                    <Button 
                      variant="outlined" 
                      size="small"
                      onClick={() => {
                        setFilters({
                          type: 'all',
                          dateRange: 'all',
                          status: 'all',
                          wallet: 'all'
                        });
                        handleFilterMenuClose();
                      }}
                    >
                      Reset
                    </Button>
                    <Button 
                      variant="contained" 
                      size="small" 
                      sx={{ ml: 1 }}
                      onClick={handleFilterMenuClose}
                    >
                      Apply
                    </Button>
                  </Box>
                </Box>
              </Menu>
            </Box>
          </Toolbar>

          {copySuccess && (
            <Alert severity="success" sx={{ mx: 2 }}>
              {copySuccess}
            </Alert>
          )}

          {error && (
            <Alert severity="error" sx={{ m: 2 }}>
              {error}
            </Alert>
          )}

          <TableContainer>
            {loading ? (
              <Box display="flex" justifyContent="center" alignItems="center" py={4}>
                <CircularProgress />
              </Box>
            ) : transactions.length === 0 ? (
              <Box textAlign="center" py={4}>
                <Typography variant="h6" color="text.secondary">
                  No transactions found
                </Typography>
                <Typography variant="body2" color="text.secondary" sx={{ mt: 1 }}>
                  Try adjusting your filters or make your first transaction
                </Typography>
                <Button 
                  variant="contained" 
                  sx={{ mt: 2 }}
                  onClick={() => navigate('/send')}
                >
                  Send Money
                </Button>
              </Box>
            ) : (
              <Table aria-label="transactions table">
                <TableHead>
                  <TableRow>
                    <TableCell 
                      onClick={() => handleSortChange('date')}
                      style={{ cursor: 'pointer' }}
                    >
                      <Box display="flex" alignItems="center">
                        Date
                        {sortField === 'date' && (
                          <IconButton size="small">
                            {sortDirection === 'asc' ? <ArrowUpward fontSize="small" /> : <ArrowDownward fontSize="small" />}
                          </IconButton>
                        )}
                      </Box>
                    </TableCell>
                    <TableCell 
                      onClick={() => handleSortChange('type')}
                      style={{ cursor: 'pointer' }}
                    >
                      <Box display="flex" alignItems="center">
                        Type
                        {sortField === 'type' && (
                          <IconButton size="small">
                            {sortDirection === 'asc' ? <ArrowUpward fontSize="small" /> : <ArrowDownward fontSize="small" />}
                          </IconButton>
                        )}
                      </Box>
                    </TableCell>
                    <TableCell 
                      onClick={() => handleSortChange('description')}
                      style={{ cursor: 'pointer' }}
                    >
                      <Box display="flex" alignItems="center">
                        Description
                        {sortField === 'description' && (
                          <IconButton size="small">
                            {sortDirection === 'asc' ? <ArrowUpward fontSize="small" /> : <ArrowDownward fontSize="small" />}
                          </IconButton>
                        )}
                      </Box>
                    </TableCell>
                    <TableCell 
                      onClick={() => handleSortChange('amount')}
                      style={{ cursor: 'pointer' }}
                      align="right"
                    >
                      <Box display="flex" alignItems="center" justifyContent="flex-end">
                        Amount
                        {sortField === 'amount' && (
                          <IconButton size="small">
                            {sortDirection === 'asc' ? <ArrowUpward fontSize="small" /> : <ArrowDownward fontSize="small" />}
                          </IconButton>
                        )}
                      </Box>
                    </TableCell>
                    <TableCell 
                      onClick={() => handleSortChange('status')}
                      style={{ cursor: 'pointer' }}
                      align="right"
                    >
                      <Box display="flex" alignItems="center" justifyContent="flex-end">
                        Status
                        {sortField === 'status' && (
                          <IconButton size="small">
                            {sortDirection === 'asc' ? <ArrowUpward fontSize="small" /> : <ArrowDownward fontSize="small" />}
                          </IconButton>
                        )}
                      </Box>
                    </TableCell>
                  </TableRow>
                </TableHead>
                <TableBody>
                  {paginatedTransactions.map((transaction) => (
                    <TableRow key={transaction.id} hover>
                      <TableCell>{transaction.formattedDate}</TableCell>
                      <TableCell>
                        <Box display="flex" alignItems="center">
                          {getTypeIcon(transaction.type)}
                          <Typography variant="body2" sx={{ ml: 1 }}>
                            {transaction.type}
                          </Typography>
                        </Box>
                      </TableCell>
                      <TableCell>{transaction.description || "—"}</TableCell>
                      <TableCell>{transaction.formattedAmount}</TableCell>
                      <TableCell>{getStatusChip(transaction.status)}</TableCell>
                      <TableCell align="right">
                        <IconButton size="small" onClick={() => handleViewDetails(transaction)}>
                          <Info fontSize="small" />
                        </IconButton>
                      </TableCell>
                    </TableRow>
                  ))}
                </TableBody>
              </Table>
            )}
          </TableContainer>

          <TablePagination
            rowsPerPageOptions={[10, 25, 50]}
            component="div"
            count={totalCount}
            rowsPerPage={rowsPerPage}
            page={page}
            onPageChange={handleChangePage}
            onRowsPerPageChange={handleChangeRowsPerPage}
          />
        </Paper>
      </Box>

      {/* Transaction Details Dialog */}
      <Dialog open={detailsOpen} onClose={handleCloseDetails} maxWidth="sm" fullWidth>
        {selectedTransaction && (
          <>
            <DialogTitle>
              Transaction Details
              <IconButton
                aria-label="close"
                onClick={handleCloseDetails}
                sx={{
                  position: 'absolute',
                  right: 8,
                  top: 8,
                }}
              >
                <Info />
              </IconButton>
            </DialogTitle>
            <DialogContent>
              <Box mb={2}>
                <Typography variant="overline" color="text.secondary">
                  Transaction ID
                </Typography>
                <Box display="flex" alignItems="center">
                  <Typography variant="body2" sx={{ mr: 1, wordBreak: 'break-all' }}>
                    {selectedTransaction.id}
                  </Typography>
                  <IconButton 
                    size="small"
                    onClick={() => copyToClipboard(selectedTransaction.id, 'Transaction ID')}
                  >
                    <ContentCopy fontSize="small" />
                  </IconButton>
                </Box>
              </Box>

              <Divider sx={{ my: 2 }} />

              <Grid container spacing={2}>
                <Grid item xs={6}>
                  <Typography variant="overline" color="text.secondary">
                    Type
                  </Typography>
                  <Typography variant="body1">
                    {selectedTransaction.type}
                  </Typography>
                </Grid>

                <Grid item xs={6}>
                  <Typography variant="overline" color="text.secondary">
                    Status
                  </Typography>
                  <Box>
                    {getStatusChip(selectedTransaction.status)}
                  </Box>
                </Grid>

                <Grid item xs={6}>
                  <Typography variant="overline" color="text.secondary">
                    Amount
                  </Typography>
                  <Typography variant="body1">
                    {formatCurrency(selectedTransaction.amount, selectedTransaction.currency)}
                  </Typography>
                </Grid>

                <Grid item xs={6}>
                  <Typography variant="overline" color="text.secondary">
                    Fee
                  </Typography>
                  <Typography variant="body1">
                    {formatCurrency(selectedTransaction.fee || 0, selectedTransaction.currency)}
                  </Typography>
                </Grid>

                <Grid item xs={12}>
                  <Typography variant="overline" color="text.secondary">
                    Date & Time
                  </Typography>
                  <Typography variant="body1">
                    {formatDate(selectedTransaction.timestamp)}
                  </Typography>
                </Grid>

                <Grid item xs={12}>
                  <Typography variant="overline" color="text.secondary">
                    Source Wallet
                  </Typography>
                  <Typography variant="body1">
                    {getWalletName(selectedTransaction.source_wallet_id)}
                  </Typography>
                  <Typography variant="body2" color="text.secondary" sx={{ wordBreak: 'break-all' }}>
                    {selectedTransaction.source_wallet_id}
                  </Typography>
                </Grid>

                {selectedTransaction.recipient_address && (
                  <Grid item xs={12}>
                    <Typography variant="overline" color="text.secondary">
                      Recipient Address
                    </Typography>
                    <Box display="flex" alignItems="center">
                      <Typography variant="body2" sx={{ mr: 1, wordBreak: 'break-all' }}>
                        {selectedTransaction.recipient_address}
                      </Typography>
                      <IconButton 
                        size="small"
                        onClick={() => copyToClipboard(selectedTransaction.recipient_address, 'Recipient Address')}
                      >
                        <ContentCopy fontSize="small" />
                      </IconButton>
                    </Box>
                  </Grid>
                )}

                {selectedTransaction.description && (
                  <Grid item xs={12}>
                    <Typography variant="overline" color="text.secondary">
                      Description
                    </Typography>
                    <Typography variant="body1">
                      {selectedTransaction.description}
                    </Typography>
                  </Grid>
                )}
              </Grid>
            </DialogContent>
            <DialogActions>
              <Button 
                startIcon={<Download />}
                onClick={handleCloseDetails}
              >
                Export
              </Button>
              <Button 
                variant="contained" 
                onClick={handleCloseDetails}
              >
                Close
              </Button>
            </DialogActions>
          </>
        )}
      </Dialog>
    </Container>
  );
};

export default Transactions;
